import React from 'react';
import AppRoutes from './routes/AppRoutes';
import Header from './components/Header';
import Footer from './components/Footer'; // 1. Додаємо імпорт футера

function App() {
  return (
    <div className="app-wrapper">
      <Header /> 
      
      <main className="main-content">
        <AppRoutes />
      </main>

      {/* 2. Додаємо Footer сюди, щоб він був у самому низу */}
      <Footer />
    </div>
  );
}

export default App;
